const ph = (s) => (s.match(/\{\d+\}/g) || []).map((x) => +x.slice(1, -1));
const maxPh = (arr) => (arr.length ? Math.max(...arr) + 1 : 0);

const stub = JSON.parse(await readFile(STUB, "utf8"));
let missing = 0, mismatch = 0;
for (const cn of Object.keys(stub.names)) {
  if (!NAMES[cn]) { console.error("missing name:", cn); missing++; }
}
for (const cn of Object.keys(stub.templates)) {
  const th = TEMPLATES[cn];
  if (!th) { console.error("missing template:", cn); missing++; continue; }
  const need = maxPh(ph(cn)), got = maxPh(ph(th));
  if (need !== got) { console.error(`placeholder mismatch (${cn.slice(0, 12)}…): skeleton ${need} vs thai ${got}`); mismatch++; }
}
if (missing || mismatch) { console.error(`FAILED: ${missing} missing, ${mismatch} mismatched`); process.exit(1); }

await writeFile(STUB, JSON.stringify({ names: NAMES, templates: TEMPLATES }, null, 2));
console.log(`OK: ${Object.keys(NAMES).length} names, ${Object.keys(TEMPLATES).length} templates`);
